ST.xhtml:
ItemLeftExitConveyor(CLK:=FIO.iAtExit);
ItemEnteringExitConveyor(CLK:=FIO.iAtSensor);
ItemLeftEntryConveyor(CLK:=FIO.iAtSensor);
SceneStarted(CLK:= FIO.iRunning);
ItemAtSensor := FIO.iVisionSensor>0;
ItemDetected(CLK:=ItemAtSensor);
FIO.oGreen := GreenCount;
FIO.oBlue := BlueCount;
FIO.oMetal := MetalCount;
StartPressed(CLK:=FIO.iStart);
StopPressed(CLK:=FIO.iStop);
ResetPressed(CLK:=FIO.iReset);
FIO.oStartLight := FALSE;
FIO.oStopLight := FALSE;
FIO.oResetLight := FALSE;
ExitConveyorStopped(CLK:=FIO.oExitConveyor);
SwitchedToAutomatic(CLk:=FIO.iAutomatic);

IF SceneStarted.Q THEN
	FIO.oStackYellow := TRUE;
END_IF

IF SwitchedToAutomatic.Q THEN
	FIO.oEntryConveyor := TRUE;
	FIO.oStackGreen := TRUE;
END_IF

IF FIO.iManual THEN
	IF StartPressed.Q THEN
		FIO.oStartLight := TRUE;
		FIO.oEntryConveyor := TRUE;
		FIO.oStackGreen := TRUE;
	END_IF
END_IF

IF ItemEnteringExitConveyor.Q THEN
	FIO.oExitConveyor := TRUE;
END_IF

IF ItemLeftEntryConveyor.Q THEN
	FIO.oEntryConveyor := FALSE;
END_IF

IF ItemDetected.Q THEN
IF FIO.iVisionSensor >=1 AND FIO.iVisionSensor <=3 THEN
	FIO.oBlueSorterTurn := TRUE;
	FIO.oBlueSorterBelt := TRUE;
	FIO.oGreenSorterTurn := FALSE;
	FIO.oGreenSorterBelt := FALSE;
	FIO.oMetalSorterTurn := FALSE;
	FIO.oMetalSorterBelt := FALSE;
	BlueCount := BlueCount+1;

ELSIF FIO.iVisionSensor >=4 AND FIO.iVisionSensor <=6 THEN
	FIO.oGreenSorterTurn := TRUE;
	FIO.oGreenSorterBelt := TRUE;
	FIO.oBlueSorterTurn := FALSE;
	FIO.oBlueSorterBelt := FALSE;
	FIO.oMetalSorterTurn := FALSE;
	FIO.oMetalSorterBelt := FALSE;
	GreenCount := GreenCount+1;

ELSIF FIO.iVisionSensor >=7 AND FIO.iVisionSensor <=9 THEN
	FIO.oMetalSorterTurn := TRUE;
	FIO.oMetalSorterBelt := TRUE;
	FIO.oBlueSorterTurn := FALSE;
	FIO.oBlueSorterBelt := FALSE;
	FIO.oGreenSorterTurn := FALSE;
	FIO.oGreenSorterBelt := FALSE;
	MetalCount := MetalCount+1;
END_IF
END_IF

IF ItemLeftExitConveyor.Q THEN
	FIO.oExitConveyor := FALSE;
END_IF

IF ExitConveyorStopped.Q THEN
	FIO.oEntryConveyor := TRUE;
END_IF

IF FIO.iAtEnd THEN
	FIO.oBlueSorterTurn := FALSE;
	FIO.oBlueSorterBelt := FALSE;
	FIO.oGreenSorterTurn := FALSE;
	FIO.oGreenSorterBelt := FALSE;
	FIO.oMetalSorterTurn := FALSE;
	FIO.oMetalSorterBelt := FALSE;
	FIO.oEntryConveyor := FALSE;
	FIO.oExitConveyor := FALSE;
	FIO.oStackGreen := FALSE;
	FIO.oStackRed := TRUE;
END_IF

IF FIO.iManual THEN
IF StopPressed.Q THEN
	FIO.oBlueSorterBelt := FALSE;
	FIO.oGreenSorterBelt := FALSE;
	FIO.oMetalSorterBelt := FALSE;
	FIO.oEntryConveyor := FALSE;
	FIO.oExitConveyor := FALSE;
	FIO.oStackGreen := FALSE;
	FIO.oStackRed := FALSE;
	FIO.oStopLight := TRUE;
END_IF
END_IF

IF FIO.iManual THEN
IF ResetPressed.Q THEN
	FIO.oBlueSorterTurn := FALSE;
	FIO.oBlueSorterBelt := FALSE;
	FIO.oGreenSorterTurn := FALSE;
	FIO.oGreenSorterBelt := FALSE;
	FIO.oMetalSorterTurn := FALSE;
	FIO.oMetalSorterBelt := FALSE;
	FIO.oEntryConveyor := FALSE;
	FIO.oExitConveyor := FALSE;
	FIO.oStackGreen := FALSE;
	FIO.oStackRed := FALSE;
	FIO.oResetLight := TRUE;
END_IF
END_IF
